tor ) -> str : """Pull a human description from the raw descriptor, or ''.""" for key in ( "description" , "desc" , "summary" ): value = descriptor . raw . get ( key ) if isinstance ( value , str ) and value : return value return "" @classmethod def _prompt ( cls , descriptor : SourceDescriptor ) -> str : """Build the capability-labeling prompt for the injected LLM.""" return ( "Name the single primary capability of this data source as a short " "snake_case verb phrase (e.g. search_crm). Respond with only the " f "label. 

 Source id: { descriptor . source_id } 
 " f "Description: { cls . _description ( descriptor ) or '(none)' } " )
